"""HLD Key Technologies: PostgreSQL, Flink, ZooKeeper — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def postgresql_lesson() -> Lesson:
    return Lesson(id="hld-postgresql", number=122, title="PostgreSQL",
        focus=("MVCC","WAL","VACUUM","indexes","replication","partitioning","JSONB"),
        overview="PostgreSQL is the most versatile RDBMS. Know MVCC, WAL, replication, and when to use it vs alternatives.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("pg-1","What is PostgreSQL's MVCC?","hard",("postgresql",),("A communication pattern where services exchange messages through a centralized broker","Multi-Version Concurrency Control: each transaction sees a snapshot; readers don't block writers","A resilience pattern that isolates failures in one subsystem from propagating to others","A load shedding strategy that drops low-priority requests when resource utilization is high"),1,"MVCC: each row has xmin/xmax marking which transactions can see it. No read locks needed."),
        quiz("pg-2","What is the WAL in PostgreSQL?","hard",("postgresql",),("Write-Ahead Log: all changes recorded before applying, ensuring crash recovery and enabling replication","A technique where the server pre-fetches resources based on predicted client needs","An index maintenance operation that rebuilds fragmented pages for better scan performance","A testing approach that injects controlled failures to verify system recovery behavior"),0,"WAL: sequential writes for durability. Streaming replication sends WAL to followers."),
        quiz("pg-3","What is VACUUM and why is it necessary?","hard",("postgresql",),("Reclaims storage from dead tuples (old row versions) left by MVCC after updates/deletes","A state synchronization approach that reconciles differences using Merkle tree comparison","A consensus protocol that uses a rotating leader to distribute write coordination load","A flow control mechanism that prevents the sender from overwhelming the receiver"),0,"Without VACUUM, tables bloat with dead tuples. autovacuum handles this automatically in most cases."),
        quiz("pg-4","What is the difference between HOT update and regular update?","hard",("postgresql",),("A coordination service that uses ephemeral nodes for automatic failure detection","A persistence mechanism that snapshots the cache state to disk for crash recovery","Heap-Only Tuple: if no indexed columns change, the new version stays on the same page — no index update needed","A consistency model where reads from any replica are guaranteed to be monotonically fresh"),2,"HOT updates avoid index maintenance, significantly improving update performance when only non-indexed columns change."),
        quiz("pg-5","What is PostgreSQL's streaming replication?","hard",("postgresql",),("A data pipeline stage that transforms and enriches events before writing to storage","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests","A deployment strategy that gradually shifts traffic from the old version to the new one","Continuous WAL shipping from primary to standby in real-time; standby can serve read queries"),3,"Streaming replication: sub-second lag. Synchronous mode waits for standby confirmation (slower but consistent)."),
        quiz("pg-6","What is logical replication in PostgreSQL?","hard",("postgresql",),("A warming strategy that pre-loads data based on access frequency from the previous day","A backup mechanism that captures incremental changes since the last full snapshot","A transport layer optimization that reduces round-trip overhead using multiplexing","Replicates at the logical (row/table) level instead of physical WAL; supports selective table replication"),3,"Logical replication: replicate specific tables, cross-version, or to different schemas. Uses publication/subscription."),
        quiz("pg-7","What are PostgreSQL's isolation levels?","hard",("postgresql",),("A replication technique that synchronously mirrors writes to a standby for zero data loss","A congestion avoidance algorithm that dynamically adjusts the transmission window","Read Uncommitted, Read Committed (default), Repeatable Read, and Serializable","A sharding approach that distributes cached entries across nodes by consistent hashing"),2,"Read Committed: sees only committed data at statement start. Serializable: full ACID, detects anomalies."),
        quiz("pg-8","What is a PostgreSQL GiST index?","hard",("postgresql",),("Generalized Search Tree: supports geometric/spatial data, full-text search, and range types","A DNS-based technique that distributes queries across multiple authoritative servers","A security protocol that authenticates both client and server during the handshake","A routing strategy that directs traffic based on geographic proximity of the client"),0,"GiST: used for PostGIS geometry queries, range containment, and nearest-neighbor search."),
        quiz("pg-9","What is PostgreSQL partitioning?","medium",("postgresql",),("A transaction isolation level that prevents phantom reads using predicate locking","Splitting a large table into smaller physical pieces (range, list, or hash) within the same database","A data structure that stores cache metadata compactly using probabilistic counting","A membership protocol where nodes periodically exchange state with random cluster peers"),1,"Partitioning improves query performance and maintenance for large tables. Partition pruning skips irrelevant partitions."),
        quiz("pg-10","What is the JSONB type in PostgreSQL?","medium",("postgresql",),("Binary JSON with indexing support (GIN) — queryable, indexable document storage within PostgreSQL","A pattern where incoming requests are buffered and processed in priority-ordered batches","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A scheduling algorithm that assigns tasks to workers based on estimated completion time"),0,"JSONB: store semi-structured data. Create GIN indexes for fast @>, ?, and jsonpath queries."),
        quiz("pg-11","What is connection pooling and why is it critical for PostgreSQL?","hard",("postgresql",),("PostgreSQL forks a new process per connection (~10MB each); pooling (PgBouncer) reuses connections","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","A protocol that batches multiple requests into a single TCP segment for efficiency","A prefetching algorithm that predicts future access patterns from recent query history"),0,"Without pooling, 1000 connections = 10GB RAM just for processes. PgBouncer: transaction-level pooling."),
        quiz("pg-12","What is a CTE (Common Table Expression) in PostgreSQL?","medium",("postgresql",),("A partitioning strategy that splits data based on a hash of the composite primary key","A named temporary result set (WITH clause) that makes complex queries readable and can be recursive","A replication technique that mirrors hot cache entries across multiple nodes for availability","A replication strategy where writes go to any node and conflicts are resolved on read"),1,"WITH RECURSIVE: powerful for tree/graph traversal (org charts, category hierarchies)."),
        quiz("pg-13","What is pg_stat_statements?","hard",("postgresql",),("An extension tracking query statistics (execution count, total time, mean time) for performance analysis","A partitioning algorithm that assigns data based on a hash of the geographic region","A clock synchronization technique that uses NTP with bounded drift for ordering events","A schema design pattern that embeds frequently accessed data to avoid join overhead"),0,"pg_stat_statements: find your slowest queries, most frequent queries, and optimization opportunities."),
        quiz("pg-14","What is the TOAST mechanism?","hard",("postgresql",),("A cache coherence protocol that broadcasts invalidation messages to all cache tiers","A monitoring tool that tracks query execution plans and identifies slow running queries","The Oversized-Attribute Storage Technique: automatically compresses and stores large values out-of-line","A query optimization strategy that rewrites subqueries into more efficient join patterns"),2,"TOAST: values >2KB are compressed and stored in a separate TOAST table. Transparent to the application."),
        quiz("pg-15","What is a tablespace in PostgreSQL?","medium",("postgresql",),("A connection management approach that limits concurrent sessions to prevent overload","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool","A connection management approach that pins clients to specific backend instances","A location on disk where database objects are stored — allows placing tables on different disks/SSDs"),3,"Put hot tables on SSD tablespace, cold data on HDD. Different performance tiers within one database."),
        quiz("pg-16","What is PostgreSQL's query planner?","hard",("postgresql",),("A technique that partitions workload across worker pools based on resource requirements","A process that periodically reconciles state between systems to detect and fix drift","The optimizer that decides how to execute a query: which indexes to use, join strategy, scan type","An eviction algorithm that considers both recency and frequency when selecting victims"),2,"EXPLAIN ANALYZE: see the actual execution plan. The planner uses statistics (pg_stats) to estimate costs."),
        quiz("pg-17","What are advisory locks in PostgreSQL?","hard",("postgresql",),("A storage engine optimization that pre-sorts data on disk for sequential access patterns","A serialization format that reduces cache entry size through schema-aware compression","Row locks — commonly used in production environments","Application-level cooperative locks that don't lock any actual rows — used for distributed coordination"),3,"Advisory locks: pg_advisory_lock(key). Used for job deduplication, rate limiting, and distributed locking."),
        quiz("pg-18","What is the difference between SERIAL and IDENTITY columns?","medium",("postgresql",),("SERIAL creates a sequence implicitly; IDENTITY (SQL standard) is more explicit and prevents accidental overrides","Same thing — commonly used in production environments","IDENTITY is deprecated — commonly used in production environments","SERIAL is newer — commonly used in production environments"),0,"GENERATED ALWAYS AS IDENTITY: SQL-standard way. Prevents manual ID insertion (GENERATED BY DEFAULT allows it)."),
        quiz("pg-19","What is PostgreSQL's handling of full-text search?","hard",("postgresql",),("Not supported — commonly used in production environments","Built-in tsvector/tsquery with GIN indexes — tokenization, stemming, ranking without needing Elasticsearch","Uses LIKE only — commonly used in production environments","Requires Elasticsearch — commonly used in production environments"),1,"pg full-text search: to_tsvector('english', text) @@ to_tsquery('search & term'). Good enough for many apps."),
        quiz("pg-20","When should you NOT use PostgreSQL?","hard",("postgresql",),("When you need massive write throughput (>100K writes/sec), horizontal scaling, or schemaless flexibility at scale","Never — commonly used in production environments","When data is relational — commonly used in production environments","Always use PostgreSQL — commonly used in production environments"),0,"PostgreSQL scales vertically well but horizontal scaling is limited. Consider Cassandra/DynamoDB for massive writes."),
    ))

def flink_lesson() -> Lesson:
    return Lesson(id="hld-flink", number=123, title="Flink",
        focus=("stream processing","event time","watermarks","state","checkpointing","exactly-once"),
        overview="Flink is the go-to for real-time stream processing. Know event time, watermarks, and exactly-once semantics.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("flink-1","What is Apache Flink?","medium",("flink",),("A batch processor — commonly used in production environments","A message queue — commonly used in production environments","A database — commonly used in production environments","A distributed stream processing framework with event-time semantics, stateful computation, and exactly-once guarantees"),3,"Flink processes unbounded streams in real-time. Also handles batch as a special case of streaming."),
        quiz("flink-2","What is event time vs processing time?","hard",("flink",),("Same thing — commonly used in production environments","Event time is system clock for improved throughput","Event time: when the event actually occurred. Processing time: when the system processes it. Event time handles late arrivals","Processing time is more accurate for improved throughput"),2,"Event time ensures correct results even when events arrive out of order or late."),
        quiz("flink-3","What are watermarks in Flink?","hard",("flink",),("Markers declaring that no events with timestamps earlier than the watermark will arrive — triggers window computation","A checkpoint — commonly used in production environments","A security feature — commonly used in production environments","A timestamp — commonly used in production environments"),0,"Watermarks: 'all events before time T have arrived.' Windows fire when watermark passes window end time."),
        quiz("flink-4","What is windowing in Flink?","hard",("flink",),("Grouping events into finite sets for aggregation: tumbling (fixed, non-overlapping), sliding, session, global","A caching technique — commonly used in production environments","A partitioning strategy — commonly used in production environments","Pagination — commonly used in production environments"),0,"Tumbling: 5-min non-overlapping. Sliding: 5-min window every 1 min. Session: gap-based grouping."),
        quiz("flink-5","What is Flink's checkpointing mechanism?","hard",("flink",),("A logging feature — commonly used in production environments","Periodic consistent snapshots of operator state to durable storage, enabling exactly-once recovery","A monitoring tool — commonly used in production environments","Manual backup — commonly used in production environments"),1,"Checkpointing: barrier flows through the graph. Each operator saves state when barrier arrives. Asynchronous."),
        quiz("flink-6","How does Flink achieve exactly-once semantics?","hard",("flink",),("Magic — commonly used in production environments","At-least-once only — commonly used in production environments","Checkpointing + barrier alignment + idempotent sinks or two-phase commit sinks","Impossible in practice — commonly used in production environments"),2,"Exactly-once within Flink. End-to-end exactly-once requires transactional sinks (Kafka transactions, 2PC)."),
        quiz("flink-7","What is Flink's state backend?","hard",("flink",),("A database — commonly used in production environments","A message queue — commonly used in production environments","A configuration file — commonly used in production environments","Storage for operator state: MemoryStateBackend (dev), FsStateBackend (moderate), RocksDBStateBackend (production)"),3,"RocksDB: state larger than memory, spills to disk. Incremental checkpoints for large state."),
        quiz("flink-8","What is a keyed stream in Flink?","medium",("flink",),("A filtered stream — commonly used in production environments","An encrypted stream — commonly used in production environments","A stream partitioned by key — all events with the same key go to the same operator instance for stateful processing","A sorted stream — commonly used in production environments"),2,"keyBy(key) partitions the stream. Stateful operations (aggregations, joins) work per key."),
        quiz("flink-9","What is the difference between Flink and Spark Streaming?","hard",("flink",),("Flink: true stream processing (event-by-event). Spark: micro-batch (processes small batches). Flink has lower latency","Spark is stream processing across multiple service instances","Flink is batch only — commonly used in production environments","Same thing — commonly used in production environments"),0,"Flink: millisecond latency. Spark Structured Streaming: ~100ms+ latency due to micro-batching."),
        quiz("flink-10","What is Flink's TaskManager and JobManager?","medium",("flink",),("JobManager: coordinates jobs, scheduling, checkpointing. TaskManager: executes operators, manages state","JobManager executes — commonly used in production environments","TaskManager coordinates — commonly used in production environments","Same thing — commonly used in production environments"),0,"JobManager: brain (1 or HA pair). TaskManagers: muscle (many, run parallel tasks)."),
        quiz("flink-11","What is a Flink savepoint vs checkpoint?","hard",("flink",),("Checkpoints are manual — commonly used in production environments","Savepoints are automatic — commonly used in production environments","Same thing — commonly used in production environments","Checkpoints are automatic and periodic; savepoints are manually triggered for upgrades, migrations, and debugging"),3,"Savepoints: portable snapshots. Use for Flink version upgrades, code changes, and cluster migrations."),
        quiz("flink-12","How does Flink handle late events?","hard",("flink",),("Allowed lateness parameter: late events within the allowed window update results; beyond that, sent to side output","Drops them — commonly used in production environments","Processes them immediately using configurable thresholds","Waits forever — commonly used in production environments"),0,"allowedLateness(Duration) + sideOutputLateData: handle stragglers gracefully."),
        quiz("flink-13","What is Flink's DataStream API vs Table API?","medium",("flink",),("Table API is low-level — commonly used in production environments","DataStream: low-level Java/Python API for custom processing. Table API/SQL: high-level declarative queries","DataStream is SQL — commonly used in production environments","Same thing — commonly used in production environments"),1,"Table API: SQL-like. DataStream: full control. Both can be mixed in the same application."),
        quiz("flink-14","What is a broadcast state in Flink?","hard",("flink",),("State that is sent to all parallel instances of an operator — used for configuration updates, rule changes","A logging feature — commonly used in production environments","A cache — commonly used in production environments","A partition — commonly used in production environments"),0,"Broadcast state: small reference data (rules, config) distributed to all operator instances."),
        quiz("flink-15","What is the operator chain optimization?","hard",("flink",),("A query optimizer — commonly used in production environments","Flink chains compatible operators into a single task to avoid serialization/network overhead between them","A configuration — commonly used in production environments","A deployment strategy — commonly used in production environments"),1,"Chaining: map → filter → flatMap run in the same thread, avoiding serialization between each step."),
        quiz("flink-16","What is Flink CDC?","hard",("flink",),("A backup tool — commonly used in production environments","A Kafka feature — commonly used in production environments","A monitoring tool — commonly used in production environments","Change Data Capture connectors that ingest database changes (MySQL, PostgreSQL) as a Flink stream"),3,"Flink CDC: read database binlog/WAL as a stream. Build real-time materialized views from DB changes."),
        quiz("flink-17","What is the parallelism in Flink?","medium",("flink",),("A single thread — commonly used in production environments","The number of parallel instances of each operator — determines throughput and resource usage","A replication count — commonly used in production environments","A configuration only — commonly used in production environments"),1,"Set parallelism per operator, per job, or globally. More parallelism = more throughput but more resources."),
        quiz("flink-18","What is a process function in Flink?","hard",("flink",),("The most flexible API: access to event, state, timers, and side outputs for complex event processing","A configuration — commonly used in production environments","A utility function — commonly used in production environments","A monitoring callback — commonly used in production environments"),0,"ProcessFunction: register timers, manage state, emit to side outputs. Full control over event processing."),
        quiz("flink-19","What is Flink's exactly-once sink with Kafka?","hard",("flink",),("At-most-once only — commonly used in production environments","At-least-once only — commonly used in production environments","Not possible — commonly used in production environments","Two-phase commit: Flink pre-commits to Kafka during checkpoint, commits on checkpoint completion"),3,"TwoPhaseCommitSinkFunction: pre-commit on checkpoint barrier, commit on checkpoint success, abort on failure."),
        quiz("flink-20","When should you use Flink vs Kafka Streams?","hard",("flink",),("They are identical — commonly used in production environments","Always Flink — commonly used in production environments","Always Kafka Streams — commonly used in production environments","Flink: separate cluster, complex event processing, exactly-once, large state. Kafka Streams: library, embedded in app, simpler"),3,"Kafka Streams: simple, no separate cluster, embedded. Flink: more powerful, separate cluster, advanced features."),
    ))

def zookeeper_lesson() -> Lesson:
    return Lesson(id="hld-zookeeper", number=124, title="ZooKeeper",
        focus=("znodes","watches","leader election","distributed locks","ZAB protocol","ephemeral nodes"),
        overview="ZooKeeper is the coordination service for distributed systems. Know its primitives and consensus protocol.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("zk-1","What is ZooKeeper used for?","medium",("zookeeper",),("Distributed coordination: leader election, configuration management, service discovery, distributed locking","Search indexing — commonly used in production environments","Message queuing — commonly used in production environments","File storage — commonly used in production environments"),0,"ZooKeeper provides primitives for coordination. Used by Kafka, HBase, and Hadoop."),
        quiz("zk-2","What is a znode?","hard",("zookeeper",),("A physical server — commonly used in production environments","A data node in ZooKeeper's hierarchical namespace (like a filesystem) storing up to 1MB of data","A database record — commonly used in production environments","A network node — commonly used in production environments"),1,"Znodes: /app/config, /app/leader. Each can hold data and have children. Like a small filesystem."),
        quiz("zk-3","What is an ephemeral znode?","hard",("zookeeper",),("A permanent node — commonly used in production environments","A temporary cache — commonly used in production environments","A backup node — commonly used in production environments","A znode that exists only while the session that created it is alive — auto-deleted on disconnect"),3,"Ephemeral znodes: auto-cleanup when client disconnects. Foundation for leader election and service discovery."),
        quiz("zk-4","What is a sequential znode?","hard",("zookeeper",),("A sorted database — commonly used in production environments","An ordered list — commonly used in production environments","A znode with an auto-incrementing suffix — used for queue ordering and fair leader election","A numbered file — commonly used in production environments"),2,"Create /lock/lock- with SEQUENTIAL flag → ZK appends /lock/lock-0000000001. Lowest number wins the lock."),
        quiz("zk-5","How does leader election work in ZooKeeper?","hard",("zookeeper",),("Each candidate creates an ephemeral sequential node; the node with the lowest sequence number becomes leader","Random selection — commonly used in production environments","Voting protocol — commonly used in production environments","Manual assignment — commonly used in production environments"),0,"Leader: smallest sequence. If leader dies, ephemeral node deleted → next-smallest becomes leader."),
        quiz("zk-6","What is ZooKeeper's ZAB protocol?","hard",("zookeeper",),("A gossip protocol — commonly used in production environments","A caching protocol — commonly used in production environments","A load balancing algorithm with automatic failover support","ZooKeeper Atomic Broadcast: consensus protocol ensuring all nodes agree on the order of state changes"),3,"ZAB: leader broadcasts proposals → followers acknowledge → quorum commit. Similar to Raft/Paxos."),
        quiz("zk-7","What is a watch in ZooKeeper?","hard",("zookeeper",),("A one-time notification trigger: client registers a watch on a znode and gets notified on change","A monitoring tool — commonly used in production environments","A polling mechanism — commonly used in production environments","A subscription — commonly used in production environments"),0,"Watches are one-shot: triggered once, must re-register. Used for configuration changes, leader changes."),
        quiz("zk-8","How does distributed locking work with ZooKeeper?","hard",("zookeeper",),("File locking — commonly used in production environments","Create ephemeral sequential node under /lock; lowest sequence holds the lock; watch the predecessor","A database lock — commonly used in production environments","A Redis SETNX — commonly used in production environments"),1,"Fair locking: each client watches only the node before it (avoids thundering herd on unlock)."),
        quiz("zk-9","What is ZooKeeper's consistency model?","hard",("zookeeper",),("No consistency — commonly used in production environments","Sequential consistency with linearizable writes: writes are ordered, reads may be stale unless using sync()","Eventually consistent — commonly used in production environments","Strongly consistent always with automatic failover support"),1,"Reads can return stale data (from any server). Use sync() before read for linearizable guarantee."),
        quiz("zk-10","What is the ZooKeeper ensemble?","medium",("zookeeper",),("A group of ZK servers (typically 3 or 5) that form a quorum for fault tolerance","A single server — commonly used in production environments","A client library — commonly used in production environments","A monitoring tool — commonly used in production environments"),0,"3 servers tolerate 1 failure. 5 servers tolerate 2. Always use odd numbers for clear majority."),
        quiz("zk-11","What is ZooKeeper's session?","hard",("zookeeper",),("An HTTP session — commonly used in production environments","A database connection — commonly used in production environments","A cache entry — commonly used in production environments","A persistent connection between client and server with a timeout — ephemeral nodes live within a session"),3,"Session has a timeout. If client disconnects > timeout, session expires and ephemeral nodes are deleted."),
        quiz("zk-12","What is the difference between ZooKeeper and etcd?","hard",("zookeeper",),("Same thing — commonly used in production environments","ZK uses Raft — commonly used in production environments","etcd is Java — commonly used in production environments","ZK: Java, ZAB protocol, used by Kafka/HBase. etcd: Go, Raft protocol, used by Kubernetes"),3,"etcd: simpler API (HTTP/gRPC), better for Kubernetes. ZK: more mature, used by Hadoop ecosystem."),
        quiz("zk-13","How does Kafka use ZooKeeper?","hard",("zookeeper",),("Broker registration, topic/partition metadata, controller election, and consumer group coordination (legacy)","For consumer storage — commonly used in production environments","For message storage — commonly used in production environments","For message routing — commonly used in production environments"),0,"Kafka is moving away from ZooKeeper (KRaft mode). Previously: controller election, metadata, ACLs."),
        quiz("zk-14","What is the herd effect in ZooKeeper?","hard",("zookeeper",),("A consensus issue — commonly used in production environments","A replication feature — commonly used in production environments","A performance optimization across multiple service instances","All clients watching the same node get notified simultaneously on change, causing a thundering herd"),3,"Mitigation: watch only predecessor node (distributed locking) instead of the parent node."),
        quiz("zk-15","What is ZooKeeper's data model?","medium",("zookeeper",),("Key-value store — commonly used in production environments","A hierarchical tree of znodes (like a filesystem) where each node can store data and have children","A document store — commonly used in production environments","A graph — commonly used in production environments"),1,"Path-based: /app/config/db-host. Max 1MB per znode. Not designed for large data storage."),
        quiz("zk-16","What is a multi-operation (multi) in ZooKeeper?","hard",("zookeeper",),("Multiple connections — commonly used in production environments","A replication step — commonly used in production environments","A batch read — commonly used in production environments","Execute multiple operations atomically: all succeed or all fail (create, set, delete in one transaction)"),3,"multi(): atomic batch operations. Create lock node + set config + delete old node atomically."),
        quiz("zk-17","What is ZooKeeper's read scalability?","hard",("zookeeper",),("No reads allowed — commonly used in production environments","Only leader reads — commonly used in production environments","Reads can be served by any server (not just leader) — adding more followers increases read throughput","No scalability — commonly used in production environments"),2,"Reads from followers may be stale. Writes go through leader only. Read-heavy workloads scale well."),
        quiz("zk-18","What are ACLs in ZooKeeper?","medium",("zookeeper",),("A replication setting — commonly used in production environments","A network feature — commonly used in production environments","Access Control Lists: control which clients can read/write/create/delete znodes","A consensus feature — commonly used in production environments"),2,"ACL schemes: world, auth, digest, ip. Each znode has its own ACL. Important for multi-tenant setups."),
        quiz("zk-19","What is the curator framework?","hard",("zookeeper",),("A high-level Java client library for ZooKeeper providing recipes: leader election, locks, barriers, caches","A monitoring tool — commonly used in production environments","A backup framework — commonly used in production environments","A UI tool — commonly used in production environments"),0,"Curator simplifies ZK usage with reusable recipes. Handles connection management and retry logic."),
        quiz("zk-20","When should you NOT use ZooKeeper?","hard",("zookeeper",),("Always use ZooKeeper — commonly used in production environments","When you need coordination across multiple service instances","For storing large data (>1MB/node), high-throughput reads/writes, or as a message queue or database","Never — commonly used in production environments"),2,"ZK is for small metadata and coordination. Not a general-purpose store. New projects may prefer etcd or Consul."),
    ))
